"use client";

import { motion, AnimatePresence } from "framer-motion";
import Link from "next/link";
import { NAV_LINKS } from "@/lib/constants";

interface MobileMenuProps {
  open: boolean;
  onClose: () => void;
}

const overlay = {
  hidden: { opacity: 0 },
  visible: { opacity: 1 },
  exit: { opacity: 0 },
};

const panel = {
  hidden: { x: "100%" },
  visible: {
    x: 0,
    transition: {
      type: "tween" as const,
      duration: 0.4,
      ease: [0.25, 0.1, 0.25, 1] as [number, number, number, number],
    },
  },
  exit: {
    x: "100%",
    transition: {
      type: "tween" as const,
      duration: 0.3,
      ease: [0.25, 0.1, 0.25, 1] as [number, number, number, number],
    },
  },
};

const item = {
  hidden: { opacity: 0, x: 30 },
  visible: (i: number) => ({
    opacity: 1,
    x: 0,
    transition: { delay: 0.1 + i * 0.06, duration: 0.4 },
  }),
};

export default function MobileMenu({ open, onClose }: MobileMenuProps) {
  const allLinks: { label: string; href: string; isParent?: boolean }[] = [];
  for (const link of NAV_LINKS) {
    if ("children" in link && link.children) {
      allLinks.push({ label: link.label, href: link.href, isParent: true });
      for (const child of link.children as ReadonlyArray<{ label: string; href: string }>) {
        allLinks.push({ label: child.label, href: child.href });
      }
    } else {
      allLinks.push({ label: link.label, href: link.href });
    }
  }

  return (
    <AnimatePresence>
      {open && (
        <>
          {/* Backdrop */}
          <motion.div
            variants={overlay}
            initial="hidden"
            animate="visible"
            exit="exit"
            className="fixed inset-0 z-[60] bg-black/60"
            onClick={onClose}
          />

          {/* Panel */}
          <motion.nav
            variants={panel}
            initial="hidden"
            animate="visible"
            exit="exit"
            className="fixed inset-y-0 right-0 z-[70] flex w-full max-w-sm flex-col bg-brand-dark"
          >
            {/* Close button */}
            <button
              onClick={onClose}
              className="absolute right-6 top-6 text-brand-cream/80 transition-colors hover:text-brand-cream"
              aria-label="Fermer le menu"
            >
              <svg
                width="28"
                height="28"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="1.5"
              >
                <path d="M18 6 6 18M6 6l12 12" />
              </svg>
            </button>

            {/* Links */}
            <div className="flex flex-1 flex-col items-start justify-center gap-6 px-10">
              {allLinks.map((link, i) => (
                <div key={link.href} className="overflow-hidden">
                  <motion.div
                    custom={i}
                    variants={item}
                    initial="hidden"
                    animate="visible"
                    exit="hidden"
                  >
                    <Link
                      href={link.href}
                      onClick={onClose}
                      className={`font-heading tracking-wide transition-colors hover:text-brand-orange block ${link.isParent
                        ? "text-xl uppercase text-brand-cream/40 mb-2 mt-4"
                        : "text-4xl text-brand-cream/90 font-light"
                        }`}
                    >
                      {link.label}
                    </Link>
                  </motion.div>
                </div>
              ))}
            </div>

            {/* CTA */}
            <div className="border-t border-white/10 p-8 origin-bottom">
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.4, duration: 0.5 }}
              >
                <Link
                  href="/reservation"
                  onClick={onClose}
                  className="block w-full rounded-sm bg-brand-orange px-6 py-4 text-center font-heading text-xl uppercase tracking-widest text-brand-dark transition-colors hover:bg-brand-orange/90 shadow-lg"
                >
                  Réserver
                </Link>
              </motion.div>
            </div>
          </motion.nav>
        </>
      )}
    </AnimatePresence>
  );
}
